extension.valueString:
/*
@internal: Potential contraindications observations
*/
define "Potential contraindications":
  ([Observation: Concepts."Potential contraindications"]).complete()

/*
@internal: Observation for currently pregnant
*/
define "CI Currently pregnant Observation":
  "Potential contraindications" O
    where O.value ~ Concepts."CI-Currently pregnant"

/*
@internal: Condition for currently pregnant
*/
define "CI Currently pregnant Condition":
  [Condition: Concepts."CI-Currently pregnant"]

/*
@internal: Condition for currently pregnant
*/
define "CI Currently pregnant Condition":
  Elements."CI Currently pregnant Condition" C
    where C.prevalenceInterval() includes Today

define "Pregnancy Status Observation":
  [Observation: Concepts."Pregnancy status"] O
    where O.status in { 'final', 'amended', 'corrected' }

/*
@input: The client is pregnant
@pseudocode: "Potential contraindications" = "Currently pregnant"
*/
define "The client is pregnant":
  exists "CI Currently pregnant Observation"
  or exists "CI Currently pregnant Condition"
  or exists WE."Pregnant Observation"

/*
@input: The client is currently pregnant
@pseudocode: "Potential contraindications" = "Currently pregnant"
@code: The client is currently pregnant-52
@decision: IMMZ.D5.DT.Hepatitis A contraindications
*/
define "The client is currently pregnant":
  Encounter."The client is pregnant"

/*
@output: Live attentuated Hepatitis A-containing vaccine is contraindicated Case 1
@pseudocode: "Immunization recommendation status" = "Contraindicated" (where "Type of hepatitis A dose" = "Live attenuated hepatitis A vaccine")
*/
define "Live attentuated Hepatitis A-containing vaccine is contraindicated Case 1":
  Encounter."The client is currently pregnant"

/*
@internal: Observation for Severely immunocompromised
*/
define "CI Severely immunocompromised Observation":
  "Potential contraindications" O
    where O.value ~ Concepts."CI-Severely immunocompromised"

/*
@internal: Observation for Severely immunocompromised
*/
define "CI Severely immunocompromised Observation":
  Elements."CI Severely immunocompromised Observation".encounterOrOnBefore(EncounterId, Today)

/*
@internal: Condition for Severely immunocompromised
*/
define "CI Severely immunocompromised Condition":
  [Condition: Concepts."CI-Severely immunocompromised"]

/*
@internal: Condition for Severely immunocompromised
*/
define "CI Severely immunocompromised Condition":
  Elements."CI Severely immunocompromised Condition" C
    where C.prevalenceInterval() includes Today

/*
@input: The client is severely immunocompromised
@pseudocode: "Potential contraindications" = "Severely immunocompromised"
*/
define "The client is severely immunocompromised":
  exists "CI Severely immunocompromised Observation"
    or exists "CI Severely immunocompromised Condition"

/*
@input: The client is severely immunocompromised
@pseudocode: "Potential contraindications" = "Severely immunocompromised"
@code: The client is severely immunocompromised-60
@decision: IMMZ.D5.DT.Hepatitis A contraindications
*/
define "The client is severely immunocompromised":
  Encounter."The client is severely immunocompromised"

/*
@output: Live attentuated Hepatitis A-containing vaccine is contraindicated Case 2
@pseudocode: "Immunization recommendation status" = "Contraindicated" (where "Type of hepatitis A dose" = "Live attenuated hepatitis A vaccine")
*/
define "Live attentuated Hepatitis A-containing vaccine is contraindicated Case 2":
  Encounter."The client is severely immunocompromised"

/*
@output: Live attentuated Hepatitis A-containing vaccine is contraindicated
@pseudocode: "Immunization recommendation status" = "Contraindicated" (where "Type of hepatitis A dose" = "Live attenuated hepatitis A vaccine")
*/
define "Live attentuated Hepatitis A-containing vaccine is contraindicated":
  "Live attentuated Hepatitis A-containing vaccine is contraindicated Case 1"
    or "Live attentuated Hepatitis A-containing vaccine is contraindicated Case 2"

/*
@output: Live attentuated Hepatitis A-containing vaccine is contraindicated Guidance
@guidance = Do not vaccinate client with hepatitis A as hepatitis A vaccination is contraindicated for pregnant client and may pose a theoretical risk to the developing fetus.
@guidance = Do not vaccinate client with hepatitis A as hepatitis A vaccination is contraindicated for severely immunocompromised clients.
*/
define "Live attentuated Hepatitis A-containing vaccine is contraindicated Guidance":
  case
    when "Live attentuated Hepatitis A-containing vaccine is contraindicated Case 1" then 'Do not vaccinate client with hepatitis A as hepatitis A vaccination is contraindicated for pregnant client and may pose a theoretical risk to the developing fetus.'
    when "Live attentuated Hepatitis A-containing vaccine is contraindicated Case 2" then 'Do not vaccinate client with hepatitis A as hepatitis A vaccination is contraindicated for severely immunocompromised clients.'
    else ''
  end

/*
@internal: Observation for Severe allergic reactions
*/
define "CI Severe allergic reactions Observation":
  "Potential contraindications" O
    where O.value ~ Concepts."CI-Severe allergic reactions"

/*
@internal: Observation for Severe allergic reactions
*/
define "CI Severe allergic reactions Observation":
  Elements."CI Severe allergic reactions Observation".encounterOrOnBefore(EncounterId, Today)

/*
@internal: Condition for Severe allergic reactions
*/
define "CI Severe allergic reactions Condition":
  [Condition: Concepts."CI-Severe allergic reactions"]

/*
@internal: Condition for Severe allergic reactions
*/
define "CI Severe allergic reactions Condition":
  Elements."CI Severe allergic reactions Condition" C
    where C.prevalenceInterval() includes Today

/*
@input: The client has history of severe allergic reactions
@pseudocode: "Potential contraindications" = "Severe allergic reactions"
*/
define "The client has history of severe allergic reactions":
  exists "CI Severe allergic reactions Observation"
    or exists "CI Severe allergic reactions Condition"

/*
@input: The client has a history of severe allergic reactions
@pseudocode: '"Potential contraindications" = "Severe allergic reactions"
@code: The client has a history of severe allergic reactions-60
@decision: IMMZ.D5.DT.Hepatitis A contraindications
*/
define "The client has a history of severe allergic reactions":
  Encounter."The client has history of severe allergic reactions"

/*
@output: Hepatitis A vaccination could be contraindicated. Clinical judgement is required. Create a clinical note
@pseudocode: "Immunization recommendation status" = "Further evaluation needed"
*/
define "Hepatitis A vaccination could be contraindicated. Clinical judgement is required. Create a clinical note":
  Encounter."The client has a history of severe allergic reactions"

/*
@output: Hepatitis A vaccination could be contraindicated. Clinical judgement is required. Create a clinical note Guidance
@guidance: Do not vaccinate client with inactivated hepatitis A vaccination if client has had a severe allergic reaction to the previous dose.
Do not vaccinate client with live attenuated hepatitis A vaccination if client has severe allergy to components included in the live attenuated hepatitis A-containing vaccines.
*/
define "Hepatitis A vaccination could be contraindicated. Clinical judgement is required. Create a clinical note Guidance":
  'Do not vaccinate client with inactivated hepatitis A vaccination if client has had a severe allergic reaction to the previous dose.
Do not vaccinate client with live attenuated hepatitis A vaccination if client has severe allergy to components included in the live attenuated hepatitis A-containing vaccines.'

/*
@dataElement: Draft Medication Request for Patient
*/
define "Draft Medication Request for Patient":
	[MedicationRequest] MR where MR.status = 'draft' and MR.intent = 'proposal'
	sort by date from (authoredOn as FHIR.dateTime) desc

/*
@internal: Draft Medication Request for Hepatitis A dose
*/
define "Draft Medication Request for Hepatitis A dose":
  Encounter."Draft Medication Request for Patient" MR
    where MR.medication in Concepts."Hepatitis A-containing vaccines"

/*
  @dynamicValue: Draft Medication Request ID for Hepatitis A dose
  */
  define "Draft Medication Request ID for Hepatitis A dose":
    First(Encounter."Draft Medication Request for Hepatitis A dose").id

/*
@description: Returns true if the given reference is to the given resourceId
@comment: Returns true if the `resourceId` parameter exactly equals the tail of the given reference.
NOTE: This function assumes resources from the same source server.
*/
define fluent function references(reference FHIR.Reference, resourceId String):
  resourceId = Last(Split(reference.reference, '/'))
